/**
 * MedX brand theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * MedX brand colors, logos, and accent rules.
 */
const BRAND_TOKENS = Object.freeze({
  primary: { value: "theme-brand-primary", scope: "theme" },
  secondary: { value: "theme-brand-secondary", scope: "theme" },
  muted: { value: "theme-brand-muted", scope: "theme" },
  accent: { value: "theme-brand-accent", scope: "theme" },
  surface: { value: "theme-brand-surface", scope: "theme" },
});

const BRAND_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const BRAND_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const brandRegistry = new Map();
const BRAND_listeners = new Set();
let BRAND_seq = 0;

function createBrandId(prefix = "medx-theme-brand") {
  BRAND_seq += 1;
  return `${prefix}-${BRAND_seq}`;
}

function registerBrand(config = {}) {
  const entryId = config.id ?? createBrandId();
  const preset = BRAND_PRESETS[config.preset ?? "default"] ?? BRAND_PRESETS.default;
  const token = BRAND_TOKENS[config.token ?? preset.token] ?? BRAND_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: BRAND_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  brandRegistry.set(entryId, entry);
  notifyBrandListeners("register", entry);
  return entry;
}

function updateBrand(id, patch = {}) {
  const entry = brandRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyBrandListeners("update", entry);
  return entry;
}

function resolveBrand(id) {
  const entry = brandRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listBrandEntries(filter = {}) {
  let items = Array.from(brandRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onBrandEvent(listener) {
  BRAND_listeners.add(listener);
  return () => BRAND_listeners.delete(listener);
}

function notifyBrandListeners(type, entry) {
  for (const listener of BRAND_listeners) {
    try {
      listener({ type, entry, registrySize: brandRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:brand] listener error", err.message);
    }
  }
}

function getBrandMetrics() {
  const items = listBrandEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(BRAND_TOKENS).length,
    presets: Object.keys(BRAND_PRESETS).length,
  };
}

async function runMedxBrand() {
  console.log("[medx:ui:theme:brand] runtime initialized");
  console.log(`[medx:ui:theme:brand] tokens=${Object.keys(BRAND_TOKENS).length} presets=${Object.keys(BRAND_PRESETS).length}`);

  const events = [];
  onBrandEvent((e) => events.push(e.type));

  const domains = Object.keys(BRAND_SUPPLY_CHAIN);
  const presets = Object.keys(BRAND_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerBrand({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/brand" },
    });
  }

  const first = listBrandEntries()[0];
  if (first) updateBrand(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getBrandMetrics();
  const resolved = first ? resolveBrand(first.id) : null;

  console.log(`[medx:ui:theme:brand] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:brand] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:brand] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:brand] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:brand] bootstrap complete");
}

module.exports = runMedxBrand;
